import type { MetricStoreName } from './store/types';

import { getRenderingMetrics } from '../getters';
import { validateIfHeadersSent } from '../utils/validations';
import { METRICS_ERRORS } from './constants';

function setRenderingMetrics<
  S extends MetricStoreName,
  P extends Record<string, unknown>,
>(name: S, props: P) {
  if (validateIfHeadersSent(METRICS_ERRORS[name])) {
    return;
  }

  const store = getRenderingMetrics(name);
  const storeProps = store.props;

  store.enabled = true;

  Object.entries(props).forEach(([key, value]) => {
    if (Array.isArray(storeProps[key]) && Array.isArray(value)) {
      storeProps[key].push(...value);
    } else {
      storeProps[key] = value;
    }
  });
}

export function setHotjarProps<P extends Record<string, unknown>>(props: P) {
  setRenderingMetrics('hotjar', props);
}

export function setGTMProps<P extends Record<string, unknown>>(props: P) {
  setRenderingMetrics('googleTagManager', props);
}

export function setQualtricsInsightsProps<P extends Record<string, unknown>>(
  props: P,
) {
  setRenderingMetrics('qualtricsInsights', props);
}
